-- General Notes & Documents
CREATE TABLE IF NOT EXISTS public.notes (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    title TEXT NOT NULL,
    content TEXT,
    color TEXT DEFAULT '#ffffff',
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Finance Tracking System
CREATE TABLE IF NOT EXISTS public.finance_profiles (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  name TEXT NOT NULL,
  type TEXT NOT NULL,
  balance NUMERIC NOT NULL DEFAULT 0,
  icon TEXT
);
CREATE TABLE IF NOT EXISTS public.finance_transactions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  transaction_date TIMESTAMPTZ NOT NULL DEFAULT now(),
  amount NUMERIC NOT NULL,
  type TEXT NOT NULL,
  category TEXT NOT NULL,
  note TEXT,
  profile_id UUID REFERENCES public.finance_profiles(id) ON DELETE SET NULL,
  payment_mode TEXT,
  location JSONB
);

-- Vehicles Trackers
CREATE TABLE IF NOT EXISTS public.vehicles (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  name TEXT NOT NULL, 
  type TEXT NOT NULL, 
  brand TEXT,
  model TEXT,
  license_plate TEXT
);

-- Storage Gallery & Molecule Models
CREATE TABLE IF NOT EXISTS public.gallery_items (
  id UUID PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  url TEXT NOT NULL,
  type TEXT NOT NULL,
  mime_type TEXT,
  filename TEXT,
  size INTEGER,
  created_at TIMESTAMPTZ DEFAULT now()
);
CREATE TABLE IF NOT EXISTS public.user_molecules (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  data JSONB NOT NULL,
  settings JSONB NOT NULL,
  is_favorite BOOLEAN DEFAULT false,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Dairy Business Bookmarks
CREATE TABLE IF NOT EXISTS public.dairy_items (
  id uuid DEFAULT uuid_generate_v4() PRIMARY KEY,
  user_id uuid REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
  name text NOT NULL,
  default_price numeric NOT NULL DEFAULT 0,
  unit text NOT NULL DEFAULT 'liter',
  icon text,
  created_at timestamptz DEFAULT now()
);
CREATE TABLE IF NOT EXISTS public.dairy_entries (
  id uuid DEFAULT uuid_generate_v4() PRIMARY KEY,
  user_id uuid REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
  item_id uuid REFERENCES public.dairy_items(id) ON DELETE SET NULL,
  quantity numeric NOT NULL,
  price_per_unit numeric NOT NULL,
  total_price numeric NOT NULL,
  entry_date date NOT NULL,
  note text,
  created_at timestamptz DEFAULT now()
);
CREATE TABLE IF NOT EXISTS public.dairy_payments (
  id uuid DEFAULT uuid_generate_v4() PRIMARY KEY,
  user_id uuid REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
  item_id uuid REFERENCES public.dairy_items(id) ON DELETE SET NULL,
  amount numeric NOT NULL,
  payment_date date NOT NULL,
  method text,
  note text,
  created_at timestamptz DEFAULT now()
);

-- Audio Voice Logs
CREATE TABLE IF NOT EXISTS public.conversations (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  owner uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  audio_url text
);
