-- Operational Functions
CREATE OR REPLACE FUNCTION increment_article_stat(p_article_url TEXT, p_stat_type TEXT, p_amount INT) RETURNS void AS $$
BEGIN EXECUTE format('UPDATE public.public_news_articles SET %I = %I + $1 WHERE article_data->>''url'' = $2', p_stat_type, p_stat_type) USING p_amount, p_article_url; END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE OR REPLACE FUNCTION mark_news_key_used(key_id UUID, cat TEXT) RETURNS void AS $$
BEGIN UPDATE public.news_api_keys SET calls_count = calls_count + 1, failure_count = 0, status = 'active', last_used_at = now(), last_used_category = cat WHERE id = key_id; END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Activity Logs Foundation
CREATE TABLE IF NOT EXISTS public.activity_logs (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    table_name TEXT NOT NULL,
    action_type TEXT NOT NULL,
    description TEXT,
    source TEXT,
    record_id TEXT,
    old_data JSONB,
    new_data JSONB,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Active Triggers
CREATE OR REPLACE FUNCTION public.log_table_activity() RETURNS TRIGGER AS $$
DECLARE
    v_source TEXT := 'Client';
    v_desc TEXT := '';
    v_record_id TEXT := NULL;
    v_old_json JSONB := NULL;
    v_new_json JSONB := NULL;
    v_id_val TEXT := NULL;
BEGIN
    IF TG_OP = 'INSERT' THEN
        BEGIN EXECUTE format('SELECT ($1).id::TEXT') INTO v_id_val USING NEW; EXCEPTION WHEN OTHERS THEN v_id_val := NULL; END;
        v_record_id := COALESCE(v_id_val, 'unknown'); v_desc := format('Inserted record %s in %s', v_record_id, TG_TABLE_NAME); v_new_json := to_jsonb(NEW);
    ELSIF TG_OP = 'UPDATE' THEN
        BEGIN EXECUTE format('SELECT ($1).id::TEXT') INTO v_id_val USING OLD; EXCEPTION WHEN OTHERS THEN v_id_val := NULL; END;
        v_record_id := COALESCE(v_id_val, 'unknown'); v_desc := format('Updated record %s in %s', v_record_id, TG_TABLE_NAME); v_old_json := to_jsonb(OLD); v_new_json := to_jsonb(NEW);
    ELSIF TG_OP = 'DELETE' THEN
        BEGIN EXECUTE format('SELECT ($1).id::TEXT') INTO v_id_val USING OLD; EXCEPTION WHEN OTHERS THEN v_id_val := NULL; END;
        v_record_id := COALESCE(v_id_val, 'unknown'); v_desc := format('Deleted record %s in %s', v_record_id, TG_TABLE_NAME); v_old_json := to_jsonb(OLD);
    END IF;
    INSERT INTO public.activity_logs (table_name, action_type, description, source, record_id, old_data, new_data)
    VALUES (TG_TABLE_NAME, TG_OP, v_desc, v_source, v_record_id, v_old_json, v_new_json);
    IF TG_OP = 'DELETE' THEN RETURN OLD; ELSE RETURN NEW; END IF;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Event trigger to auto-bind to new tables
CREATE OR REPLACE FUNCTION public.attach_trigger_to_new_table() RETURNS event_trigger AS $$
DECLARE
    obj record;
    table_name text;
    trigger_name text;
BEGIN
    FOR obj IN SELECT * FROM pg_event_trigger_ddl_commands() WHERE command_tag = 'CREATE TABLE'
    LOOP
        table_name := obj.object_identity; trigger_name := 'trigger_log_' || replace(table_name, 'public.', '');
        EXECUTE format('CREATE TRIGGER %I AFTER INSERT OR UPDATE OR DELETE ON %s FOR EACH ROW EXECUTE PROCEDURE public.log_table_activity();', trigger_name, table_name);
    END LOOP;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;
DROP EVENT TRIGGER IF EXISTS on_table_create;
CREATE EVENT TRIGGER on_table_create ON ddl_command_end WHEN TAG IN ('CREATE TABLE') EXECUTE PROCEDURE public.attach_trigger_to_new_table();

-- Admin Utility Functions
CREATE OR REPLACE FUNCTION admin_drop_table(target_table_name text) RETURNS void AS $$
BEGIN EXECUTE format('DROP TABLE IF EXISTS public.%I CASCADE', target_table_name); END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE OR REPLACE FUNCTION admin_truncate_and_reset(target_table_name text, reset_sequence boolean DEFAULT true) RETURNS void AS $$
BEGIN
    IF reset_sequence THEN EXECUTE format('TRUNCATE TABLE public.%I RESTART IDENTITY CASCADE', target_table_name);
    ELSE EXECUTE format('TRUNCATE TABLE public.%I CASCADE', target_table_name); END IF;
    INSERT INTO public.activity_logs (table_name, action_type, description, source) VALUES (target_table_name, 'TRUNCATE', format('Table %I truncated by Admin', target_table_name), 'Admin');
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE OR REPLACE FUNCTION get_database_analytics()
RETURNS TABLE(table_name text, is_public boolean, count bigint, last_used timestamptz) AS $$
DECLARE r RECORD; t_count bigint; t_latest timestamptz;
BEGIN
  FOR r IN SELECT c.relname as name, (SELECT count(*) > 0 FROM pg_policy WHERE polrelid = c.oid AND polname ILIKE '%public%') as is_pub FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace WHERE n.nspname = 'public' AND c.relkind = 'r' AND c.relname NOT ILIKE 'pg_%'
  LOOP
    EXECUTE format('SELECT count(*) FROM public.%I', r.name) INTO t_count;
    EXECUTE format('SELECT MAX(created_at) FROM public.activity_logs WHERE table_name = %L', r.name) INTO t_latest;
    table_name := r.name; is_public := r.is_pub; count := t_count; last_used := t_latest; RETURN NEXT;
  END LOOP;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

